function ScoreBadge({ score, size = "sm" }: { score: number; size?: "sm" | "xs" }) {
  if (score >= 90) {
    return (
      <span className={`inline-flex items-center gap-1 ${size === "xs" ? "px-2 py-0.5 text-[10px]" : "px-2.5 py-1 text-xs"} rounded-full bg-neon-cyan/10 border border-neon-cyan/40 text-neon-cyan font-bold shadow-[0_0_10px_rgba(6,182,212,0.2)] backdrop-blur-sm`}>
        <span className="material-symbols-outlined text-[14px]">auto_awesome</span>
        {score}%
      </span>
    );
  }
  if (score >= 80) {
    return (
      <span className={`inline-flex items-center gap-1 ${size === "xs" ? "px-2 py-0.5 text-[10px]" : "px-2 py-1 text-xs"} rounded-full bg-glass-200 border border-glass-stroke text-lavender-300 font-bold`}>
        {score}%
      </span>
    );
  }
  if (score >= 70) {
    return (
      <span className={`inline-flex items-center gap-1 ${size === "xs" ? "px-2 py-0.5 text-[10px]" : "px-2 py-1 text-xs"} rounded-full bg-glass-200 border border-glass-stroke text-slate-400 font-bold`}>
        {score}%
      </span>
    );
  }
  return (
    <span className={`inline-flex items-center gap-1 ${size === "xs" ? "px-2 py-0.5 text-[10px]" : "px-2 py-1 text-xs"} rounded-full bg-glass-200 border border-glass-stroke text-slate-500 font-bold`}>
      {score}%
    </span>
  );
}

function MatchSection({ label, items, color }: { label: string; items: string[]; color: "emerald" | "amber" }) {
  const dotColor = color === "emerald" ? "bg-emerald-400 shadow-[0_0_8px_rgba(52,211,153,0.8)]" : "bg-amber-400 shadow-[0_0_8px_rgba(251,191,36,0.8)]";
  const borderColor = color === "emerald" ? "border-emerald-500/20" : "border-amber-500/20";
  const textColor = color === "emerald" ? "text-emerald-400 drop-shadow-[0_0_5px_rgba(52,211,153,0.5)]" : "text-amber-400 drop-shadow-[0_0_5px_rgba(251,191,36,0.5)]";
  const icon = color === "emerald" ? "check_circle" : "warning";

  return (
    <div className={`bg-black/20 rounded-xl p-4 border ${borderColor} backdrop-blur-sm shadow-inner`}>
      <h4 className={`text-sm font-bold ${textColor} mb-3 flex items-center gap-2`}>
        <span className="material-symbols-outlined text-[18px]">{icon}</span> {label}
      </h4>
      <ul className="space-y-2">
        {items.map((item, i) => (
          <li key={i} className="text-xs text-lavender-200 flex items-start gap-2">
            <span className={`w-1.5 h-1.5 ${dotColor} rounded-full mt-1.5 shrink-0`}></span>
            {item}
          </li>
        ))}
      </ul>
    </div>
  );
}

